INSERT INTO `strategy_def` (`id`, `strategy_name`, `version`, `description`, `buy_rules`, `sell_rules`, `position_rules`, `special_rules`, `created_at`, `updated_at`) VALUES (2, '稳健网格', 'v3.1', 'v3.0 + 亏损清仓当日不重复买入', '情绪≤-0.8 且 当日跌幅≥1%(亏损清仓当日跳过)', '情绪≥1.0(清仓) | 盈利≥2%(卖一半) | 亏损≥3%(清仓)', '全仓50%(每笔投入上限10000元)', '亏损清仓当日不再买入', '2026-05-01 20:18:46', '2026-05-01 20:18:46');
INSERT INTO `strategy_def` (`id`, `strategy_name`, `version`, `description`, `buy_rules`, `sell_rules`, `position_rules`, `special_rules`, `created_at`, `updated_at`) VALUES (3, '稳健网格', 'v3.2', '分批建仓：信号触发先买半仓，再跌加仓', '情绪≤-0.8 且 当日跌幅≥1%(买50%即5000)；持仓后若浮亏≥3%且情绪仍≤-0.8则加仓另外50%', '情绪≥1.0(清仓) | 盈利≥2%(卖一半) | 亏损≥5%(清仓)', '分批建仓：首批5000元，浮亏3%后补5000，上限10000', '亏损清仓当日不再买入', '2026-05-01 20:18:46', '2026-05-01 20:18:46');
INSERT INTO `strategy_def` (`id`, `strategy_name`, `version`, `description`, `buy_rules`, `sell_rules`, `position_rules`, `special_rules`, `created_at`, `updated_at`) VALUES (4, '稳健网格', 'v3.3', '扩大止损线：-5%才清仓', '情绪≤-0.8 且 当日跌幅≥1%', '情绪≥1.0(清仓) | 盈利≥2%(卖一半) | 亏损≥5%(清仓)', '全仓50%(每笔投入上限10000元)', '亏损清仓当日不再买入；止损放宽到-5%', '2026-05-01 20:18:46', '2026-05-01 20:18:46');
INSERT INTO `strategy_def` (`id`, `strategy_name`, `version`, `description`, `buy_rules`, `sell_rules`, `position_rules`, `special_rules`, `created_at`, `updated_at`) VALUES (5, '稳健网格', 'v3.4', '情绪深度分档：越冷买越多', '情绪≤-0.8(买5000) | 情绪≤-1.3(买10000)', '情绪≥1.0(清仓) | 盈利≥2%(卖一半) | 亏损≥3%(清仓)', '情绪-0.8~-1.2买5000元；情绪-1.2以下买10000元', '亏损清仓当日不再买入；按情绪深度决定仓位', '2026-05-01 20:18:46', '2026-05-01 20:18:46');
