-- === strategy_def (5 rows) ===
DROP TABLE IF EXISTS `strategy_def`;
CREATE TABLE `strategy_def` (
  `id` int NOT NULL AUTO_INCREMENT,
  `strategy_name` varchar(100) NOT NULL,
  `version` varchar(20) NOT NULL,
  `description` text,
  `buy_rules` text,
  `sell_rules` text,
  `position_rules` text,
  `special_rules` text,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === backtest_results (30 rows) ===
DROP TABLE IF EXISTS `backtest_results`;
CREATE TABLE `backtest_results` (
  `id` int NOT NULL AUTO_INCREMENT,
  `strategy_id` int NOT NULL,
  `fund_code` varchar(10) NOT NULL,
  `period_label` varchar(20) DEFAULT NULL,
  `initial_capital` decimal(12,2) DEFAULT NULL,
  `final_value` decimal(12,2) DEFAULT NULL,
  `total_return` decimal(8,2) DEFAULT NULL,
  `total_profit` decimal(12,2) DEFAULT NULL,
  `max_drawdown` decimal(8,2) DEFAULT NULL,
  `trade_count` int DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_strategy_fund_period` (`strategy_id`,`fund_code`,`period_label`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

